import boto3
import sys

def create_sns_subscription(topic_arn, protocol, endpoint):
    sns_client = boto3.client('sns')
    
    response = sns_client.subscribe(
        TopicArn=topic_arn,
        Protocol=protocol,
        Endpoint=endpoint
    )
    
    return response

def main():
    print("SNS Subscription Manager")
    print("-" * 50)
    
    topic_arn = input("Enter SNS Topic ARN: ").strip()
    
    if not topic_arn:
        print("Topic ARN is required!")
        sys.exit(1)
    
    while True:
        print("\nSupported protocols: email, email-json, sms, sqs, application, lambda, https, http")
        protocol = input("Enter protocol (or 'quit' to exit): ").strip().lower()
        
        if protocol == 'quit':
            break
        
        endpoint = input("Enter endpoint URL/address: ").strip()
        
        if not endpoint:
            print("Endpoint cannot be empty!")
            continue
        
        try:
            response = create_sns_subscription(topic_arn, protocol, endpoint)
            print(f"\nSubscription created successfully!")
            print(f"Subscription ARN: {response.get('SubscriptionArn', 'pending confirmation')}")
        except Exception as e:
            print(f"Error creating subscription: {str(e)}")
    
    print("\nExiting SNS Subscription Manager")

if __name__ == "__main__":
    main()